# Function to assign hazard level based on magnitude
def assign_hazard_level(magnitude):
    if magnitude < 6.0:
        return 0
    elif 6.0 <= magnitude < 7.0:
        return 1
    else:
        return 2

# Add hazard_level to each entry
for entry in data:
    entry["Hazard_Level"] = assign_hazard_level(entry["Mag"])

# Write to CSV
with open("earthquakes.csv", "w", newline="") as csvfile:
    fieldnames = ["Magnitude", "UTC_Date_Time", "Latitude", "Longitude", "Depth", "Region", "Hazard_Level"]
    writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
    
    writer.writeheader()
    for entry in data:
        writer.writerow({
            "Magnitude": entry["Mag"],
            "UTC_Date_Time": entry["UTC_Date_Time"],
            "Latitude": entry["Lat"],
            "Longitude": entry["Lon"],
            "Depth": entry["Depth"],
            "Region": entry["Region"],
            "Hazard_Level": entry["Hazard_Level"]
        })

print("CSV file 'earthquakes.csv' has been created successfully.")